  elsa_helena_karlsson:{name:"Elsa Helena",role:"Farmor",born:"1920-09-24",status:"confirmed",place:"Balg nr 3, Torpa",facts:[["Födelseförsamling","Torpa (N)"],["Bostad i barndomen","Balg nr 3, Torpa"],["Tvilling","Karin Linnea"],["Källa","Torpa (N) CI:5 (1917-1944), Bild 110, Sida 7, födelsenotis nr 10"]],story:["Elsa Helena är Göran Nilssons mor och därmed farmor på Axels fars sida.","Hon föds 24 september 1920 i Torpa och återfinns i familjen på Balg nr 3. Födelsenotisen anger föräldrarna Karl Karlsson och Elemina Karlsdotter.","Elsa Helena är tvilling med Karin Linnea."],timeline:[["1920-09-24","Föds i Torpa."],["1920","Familjen bor på Balg nr 3 i Torpa."]],parents:["karl_karlsson","elemina_karlsdotter"],children:["goran_nilsson"]},
