  sonja_ingeborg_karlsson:{name:"Sonja Ingeborg Karlsson",role:"Syskon till Elsa",born:"1923-05-20",status:"confirmed",place:"Torpa",facts:[["Födelseförsamling","Torpa"],["Källa","Församlingsbok/husförhörssida för Balg nr 3, sida 34"]],story:["Sonja Ingeborg är dotter till Karl Karlsson och Elemina Karlsdotter, född 20 maj 1923 i Torpa."],parents:["karl_karlsson","elemina_karlsdotter"],children:[]},

